  CONSTRAINT `compra_lineas_chk_1` CHECK ((`cantidad` > 0)),
  CONSTRAINT `compra_lineas_chk_2` CHECK ((`precio_unitario` > 0))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
