--
-- Table structure for table `pedidos`
--

DROP TABLE IF EXISTS `pedidos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pedidos` (
  `id` int NOT NULL AUTO_INCREMENT,
  `cliente_id` int NOT NULL,
  `usuario_asignado_id` int DEFAULT NULL,
  `pax` int NOT NULL,
  `fecha_pedido` datetime NOT NULL,
  `observaciones` text,
  `status` enum('nuevo','preparando','listo','entregado','cancelado') DEFAULT 'nuevo',
  `entregado` tinyint(1) DEFAULT '0',
  `recogido` tinyint(1) DEFAULT '0',
  `local_recogida` tinyint(1) DEFAULT '0',
  `review` int DEFAULT NULL,
  `comentarios_recogida` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_fecha` (`fecha_pedido`),
  KEY `idx_cliente` (`cliente_id`),
  KEY `idx_status` (`status`),
  KEY `idx_usuario` (`usuario_asignado_id`),
  CONSTRAINT `pedidos_ibfk_1` FOREIGN KEY (`cliente_id`) REFERENCES `clientes` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `pedidos_ibfk_2` FOREIGN KEY (`usuario_asignado_id`) REFERENCES `usuarios` (`id`) ON DELETE SET NULL,
  CONSTRAINT `pedidos_chk_1` CHECK ((`pax` > 0)),
  CONSTRAINT `pedidos_chk_2` CHECK (((`review` is null) or ((`review` >= 1) and (`review` <= 5))))
) ENGINE=InnoDB AUTO_INCREMENT=2411 DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

